"""Adapter layer bridging LangChain's tool system to OpenCode's execution engine.

This adapter provides:
1. Wraps OpenCode tools as LangChain BaseTool instances
2. Auto-generates OpenAI-style schemas for model prompting
3. Robust parsing using LangChain's proven parsers
4. Falls back to OpenCode's format_translator for quirky model outputs
"""

from typing import Dict, Any, List, Optional, Callable
import json
from pydantic import BaseModel, Field

from .langchain_tools.base import BaseTool, StructuredTool
from .langchain_tools.function_calling import convert_to_openai_function
from .tools import ToolManager


class LangChainToolAdapter:
    """Adapts LangChain's tool system to OpenCode's execution engine.

    This provides a layered approach:
    1. Primary: LangChain's parsers (handles standard formats)
    2. Fallback: OpenCode's format_translator (handles quirky formats like ***file_read***)
    """

    def __init__(self, tool_manager: ToolManager):
        """Initialize adapter with OpenCode's tool manager.

        Args:
            tool_manager: OpenCode's existing ToolManager instance
        """
        self.tool_manager = tool_manager
        self.langchain_tools: Dict[str, BaseTool] = {}
        self._setup_tools()

    def _setup_tools(self):
        """Convert all OpenCode tools to LangChain BaseTool instances."""
        # Get all available tools from tool manager
        all_tool_names = self.tool_manager.get_all_tool_names()

        for tool_name in all_tool_names:
            # Skip if already wrapped
            if tool_name in self.langchain_tools:
                continue

            # Create a LangChain tool wrapper
            lc_tool = self._create_langchain_tool(tool_name)
            if lc_tool:
                self.langchain_tools[tool_name] = lc_tool

    def _create_langchain_tool(self, tool_name: str) -> Optional[BaseTool]:
        """Create a LangChain BaseTool for an OpenCode tool.

        Args:
            tool_name: Name of the OpenCode tool

        Returns:
            LangChain BaseTool instance or None if creation fails
        """
        try:
            # Get tool schema from OpenCode
            schemas = self.tool_manager.get_tool_schemas()
            tool_schema = next((s for s in schemas if s.get('function', {}).get('name') == tool_name), None)

            if not tool_schema:
                return None

            func_def = tool_schema.get('function', {})
            description = func_def.get('description', f'Execute {tool_name}')
            parameters = func_def.get('parameters', {})

            # Create a simple Pydantic model from the schema
            args_schema = self._schema_to_pydantic(tool_name, parameters)

            # Create execution function that calls OpenCode's tool manager
            async def execute_func(**kwargs) -> str:
                """Execute the OpenCode tool."""
                result = await self.tool_manager.execute_tool(tool_name, kwargs)
                if result.success:
                    return result.output
                else:
                    return f"Error: {result.error}"

            # Wrap as StructuredTool
            return StructuredTool(
                name=tool_name,
                description=description,
                args_schema=args_schema,
                coroutine=execute_func,
            )

        except Exception as e:
            print(f"Warning: Could not create LangChain tool for '{tool_name}': {e}")
            return None

    def _schema_to_pydantic(self, tool_name: str, schema: Dict) -> type[BaseModel]:
        """Convert JSON schema to Pydantic model.

        Args:
            tool_name: Name of the tool (for the model class name)
            schema: JSON schema defining parameters

        Returns:
            Pydantic BaseModel class
        """
        # Extract properties and required fields
        properties = schema.get('properties', {})
        required = schema.get('required', [])

        # Build field definitions
        fields = {}
        for field_name, field_schema in properties.items():
            field_type = self._json_type_to_python(field_schema.get('type', 'string'))
            field_description = field_schema.get('description', '')

            # Determine if field is required
            if field_name in required:
                fields[field_name] = (field_type, Field(..., description=field_description))
            else:
                fields[field_name] = (Optional[field_type], Field(None, description=field_description))

        # Create dynamic Pydantic model
        model_name = f"{tool_name.title().replace('_', '')}Args"
        return type(model_name, (BaseModel,), {'__annotations__': {k: v[0] for k, v in fields.items()}, **{k: v[1] for k, v in fields.items()}})

    def _json_type_to_python(self, json_type: str) -> type:
        """Convert JSON schema type to Python type.

        Args:
            json_type: JSON schema type string

        Returns:
            Python type
        """
        type_map = {
            'string': str,
            'integer': int,
            'number': float,
            'boolean': bool,
            'array': list,
            'object': dict,
        }
        return type_map.get(json_type, str)

    def get_tool_schemas_for_model(self) -> List[Dict]:
        """Get OpenAI-style function schemas for model prompting.

        Uses LangChain's convert_to_openai_function to generate properly
        formatted schemas that work with multiple model providers.

        Returns:
            List of OpenAI-style function schemas
        """
        schemas = []
        for tool in self.langchain_tools.values():
            try:
                schema = convert_to_openai_function(tool)
                schemas.append(schema)
            except Exception as e:
                print(f"Warning: Could not generate schema for tool '{tool.name}': {e}")

        return schemas

    def parse_and_validate(self, model_output: str) -> Optional[Dict[str, Any]]:
        """Parse model output using LangChain's parsers with fallback.

        Tries LangChain's proven parsers first, then falls back to OpenCode's
        format_translator for quirky model outputs.

        Args:
            model_output: Raw text output from the model

        Returns:
            Parsed tool call dict or None if no tool call detected
        """
        # Try LangChain's JSON parser first (most common)
        try:
            from .langchain_tools.parsers import JsonOutputToolsParser
            parser = JsonOutputToolsParser()
            parsed = parser.parse(model_output)
            if parsed:
                return self._normalize_parsed_result(parsed)
        except Exception:
            pass

        # Try parsing as raw JSON
        try:
            import json
            parsed = json.loads(model_output.strip())
            if isinstance(parsed, dict) and 'name' in parsed:
                return {
                    'type': 'tool_call',
                    'name': parsed['name'],
                    'args': parsed.get('arguments', parsed.get('args', {}))
                }
        except:
            pass

        # Fall back to OpenCode's format_translator for quirky formats
        try:
            from .format_translator import FormatTranslator
            translator = FormatTranslator()
            result = translator.translate_tool_call(model_output)
            if result:
                return result
        except Exception as e:
            print(f"Warning: Both LangChain and OpenCode parsers failed: {e}")

        return None

    def _normalize_parsed_result(self, parsed: Any) -> Optional[Dict[str, Any]]:
        """Normalize parsed result to OpenCode's expected format.

        Args:
            parsed: Result from LangChain parser

        Returns:
            Normalized dict with type, name, args
        """
        if isinstance(parsed, list) and len(parsed) > 0:
            parsed = parsed[0]  # Take first tool call

        if isinstance(parsed, dict):
            return {
                'type': 'tool_call',
                'name': parsed.get('name', parsed.get('type', '')),
                'args': parsed.get('arguments', parsed.get('args', {}))
            }

        return None

    def get_tool(self, tool_name: str) -> Optional[BaseTool]:
        """Get a specific LangChain tool by name.

        Args:
            tool_name: Name of the tool

        Returns:
            LangChain BaseTool instance or None
        """
        return self.langchain_tools.get(tool_name)

    def list_tools(self) -> List[str]:
        """Get list of all available tool names.

        Returns:
            List of tool names
        """
        return list(self.langchain_tools.keys())
